// Recursively collect all email-keyed objects from any depth
function collectLeads(obj, results = {}) {
  if (!obj || typeof obj !== "object") return results;

  for (const key in obj) {
    const value = obj[key];

    if (key.includes("@") && typeof value === "object") {
      results[key] = value;
    } else if (typeof value === "object") {
      collectLeads(value, results);
    }
  }
  return results;
}

// Step 1: Get full JSON
const raw = $input.first().json;

// Step 2: Collect all leads no matter how deeply nested
const allLeadsObj = collectLeads(raw);
const records = Object.entries(allLeadsObj).map(([email, lead]) => ({
  email,
  ...lead
}));

// Step 3: Filter ONLY Gmail, Yahoo, Hotmail
const publicDomains = ["gmail.com", "yahoo.com", "hotmail.com"];

const qualifiedLeads = records
  .filter(lead => {
    if (!lead.email || !lead.email.includes("@")) return false;
    const domain = lead.email.split("@")[1].toLowerCase();
    return !publicDomains.includes(domain);
  })
  .map(lead => {
    const primaryExp = lead.experience?.[0]?.company;

    return {
      email: lead.email,
      company_name: primaryExp?.name || lead.job_company_name || null,
      company_domain: primaryExp?.website || lead.job_company_website || null,
      employee_count: primaryExp?.size || lead.job_company_size || null,
      industry: primaryExp?.industry || lead.job_company_industry || null,
      location: primaryExp?.location?.name || lead.job_company_location_name || null
    };
  });

// Step 4: Return ALL qualified leads
return qualifiedLeads.map(item => ({ json: item }));
